import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate a discount?", a: "Multiply the original price by the discount percentage to find the savings, then subtract that amount from the original price." },
  { q: "How do you find the price after a percentage discount?", a: "Price after discount equals original price multiplied by one minus the discount rate." },
  { q: "How do you calculate the original price from a discounted price?", a: "Divide the final price by one minus the discount rate to reverse the discount and find the original price." },
  { q: "What is the difference between discount and markdown?", a: "A discount is a price reduction offered to a buyer. A markdown is often a seller's permanent or inventory-driven reduction from the original price." },
  { q: "How do you calculate multiple discounts?", a: "Apply each discount one after another. Two discounts of 20% and 10% are not 30% total; they leave 72% of the original price." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function DiscountCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState("percent");
  const [original, setOriginal] = useState(100);
  const [discountPercent, setDiscountPercent] = useState(25);
  const [discountAmount, setDiscountAmount] = useState(20);
  const [finalPrice, setFinalPrice] = useState(75);

  const result = useMemo(() => {
    if (mode === "reverse") {
      const originalPrice = discountPercent >= 100 ? 0 : finalPrice / (1 - discountPercent / 100);
      return { original: originalPrice, saved: originalPrice - finalPrice, final: finalPrice, percent: discountPercent };
    }
    const saved = mode === "amount" ? discountAmount : original * discountPercent / 100;
    const final = Math.max(0, original - saved);
    const percent = original ? saved / original * 100 : 0;
    return { original, saved, final, percent };
  }, [mode, original, discountPercent, discountAmount, finalPrice]);

  const priceRows = [25, 50, 100, 250, 500, 1000];

  return (
    <>
      <SEOHead title="Free Discount Calculator Online - Calculate Price After Discount Instantly | CalcHive" description="Free online discount calculator. Calculate the final price after any discount percentage, total savings and original price from discounted price instantly. 100% free, no signup required." canonical="/discount-calculator" keywords="free discount calculator, price after discount calculator free online, percent off calculator free, sale price calculator free, how much do I save calculator free" category="Financial Calculators" breadcrumbName="Free Discount Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Discount Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate sale price, savings, percentage saved, or reverse the discount to find the original price.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value)} className={inputClass}><option value="percent">Discount percentage</option><option value="amount">Discount amount</option><option value="reverse">Find original price</option></select></div>
            {mode !== "reverse" && <div><label className="text-sm font-semibold text-foreground block mb-2">Original price</label><input type="number" value={original} onChange={(e) => setOriginal(Number(e.target.value))} className={inputClass} /></div>}
            {mode !== "amount" && <div><label className="text-sm font-semibold text-foreground block mb-2">Discount percentage</label><input type="number" value={discountPercent} onChange={(e) => setDiscountPercent(Number(e.target.value))} className={inputClass} /></div>}
            {mode === "amount" && <div><label className="text-sm font-semibold text-foreground block mb-2">Discount amount</label><input type="number" value={discountAmount} onChange={(e) => setDiscountAmount(Number(e.target.value))} className={inputClass} /></div>}
            {mode === "reverse" && <div><label className="text-sm font-semibold text-foreground block mb-2">Final price</label><input type="number" value={finalPrice} onChange={(e) => setFinalPrice(Number(e.target.value))} className={inputClass} /></div>}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Final Price</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.final)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Original price</p><p className="text-lg font-extrabold text-foreground">{money(result.original)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Amount saved</p><p className="text-lg font-extrabold text-foreground">{money(result.saved)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Percentage saved</p><p className="text-lg font-extrabold text-foreground">{pct(result.percent)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Price After Discount for Free</h2><p className="text-muted-foreground leading-relaxed">Enter the original price and either a percentage discount or discount amount to calculate the sale price instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Find Original Price From a Discounted Price</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Discount Reference - Price After Discount</caption><thead className="bg-muted/60"><tr>{["Original Price", "10% Off", "20% Off", "30% Off", "50% Off", "You Save at 30%"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{priceRows.map((p) => <tr key={p}><td className="py-2.5 px-3 font-semibold">{money(p)}</td><td className="py-2.5 px-3">{money(p * 0.9)}</td><td className="py-2.5 px-3">{money(p * 0.8)}</td><td className="py-2.5 px-3">{money(p * 0.7)}</td><td className="py-2.5 px-3">{money(p * 0.5)}</td><td className="py-2.5 px-3">{money(p * 0.3)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Sale Price Calculator for Shoppers and Businesses</h2><p className="text-muted-foreground leading-relaxed">Use this discount calculator for sales, markdowns, ecommerce pricing, coupons, and quick shopping comparisons.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/discount-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


